import 'bootstrap/dist/css/bootstrap.min.css';
import { BrowserRouter, Route, Routes } from 'react-router-dom';
import ProtectedRoute from './components/ProtectedRoute';
import { AuthProvider } from './context/AuthContext';
import MainLayout from './layouts/MainLayout';
import HomePage from './pages/HomePage';
import LoginPage from './pages/auth/LoginPage';
import AdminDashboard from './pages/admin/AdminDashboard';
import SupportDashboard from './pages/support/SupportDashboard';
import DeveloperDashboard from './pages/developer/DeveloperDashboard';
import GeneralDashboard from './pages/general/GeneralDashboard';

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route path="/login" element={<LoginPage />} />
          <Route path="/" element={<MainLayout />}>
            <Route index element={<HomePage />} />
            <Route path="admin" element={<ProtectedRoute roles={['ADMIN']}><AdminDashboard /></ProtectedRoute>} />
            <Route path="support" element={<ProtectedRoute roles={['SUPPORT']}><SupportDashboard /></ProtectedRoute>} />
            <Route path="developer" element={<ProtectedRoute roles={['DEVELOPER']}><DeveloperDashboard /></ProtectedRoute>} />
            <Route path="general" element={<ProtectedRoute roles={['GENERAL']}><GeneralDashboard /></ProtectedRoute>} />
          </Route>
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}
